class RestrictedNodeVisitor(ast.NodeVisitor):
    """Visitor to check for dangerous AST nodes"""
    def __init__(self):
        self.is_safe = True
        self.error_message = None

    def visit_Import(self, node):
        self.is_safe = False
        self.error_message = 'Import statements are not allowed'
        return node

    def visit_ImportFrom(self, node):
        self.is_safe = False
        self.error_message = 'Import statements are not allowed'
        return node

    def visit_Call(self, node):
        if isinstance(node.func, ast.Name):
            if node.func.id in ('__import__', 'eval', 'exec', 'compile', 'open', 'input', 'globals', 'locals', 'vars', '__builtins__'):
                self.is_safe = False
                self.error_message = 'This function is not allowed'
                return node
        if isinstance(node.func, ast.Attribute):
            if node.func.attr in ('__getattribute__', '__setattr__', '__delattr__'):
                self.is_safe = False
                self.error_message = 'This function is not allowed'
                return node
        self.generic_visit(node)
        return node

    def visit_Attribute(self, node):
        if node.attr.startswith('_'):
            self.is_safe = False
            self.error_message = 'Access to private attributes is not allowed'
            return node
        self.generic_visit(node)
        return node

class RestrictedCodeExecutor:
    """Safely execute restricted AST code"""

    @staticmethod
    def execute(tree, restricted_globals, restricted_locals):
        """Execute AST tree in restricted environment"""
        old_stdout = sys.stdout
        sys.stdout = StringIO()

        try:
            RestrictedCodeExecutor._execute_node(tree, restricted_globals, restricted_locals)
            output = sys.stdout.getvalue()
            return output
        finally:
            sys.stdout = old_stdout

    @staticmethod
    def _execute_node(node, restricted_globals, restricted_locals):
        """Recursively execute AST nodes safely"""
        if isinstance(node, ast.Module):
            for stmt in node.body:
                RestrictedCodeExecutor._execute_node(stmt, restricted_globals, restricted_locals)
        elif isinstance(node, ast.Expr):
            RestrictedCodeExecutor._evaluate_expr(node.value, restricted_globals, restricted_locals)
        elif isinstance(node, ast.Assign):
            value = RestrictedCodeExecutor._evaluate_expr(node.value, restricted_globals, restricted_locals)
            for target in node.targets:
                if isinstance(target, ast.Name):
                    restricted_locals[target.id] = value
        elif isinstance(node, ast.For):
            iter_val = RestrictedCodeExecutor._evaluate_expr(node.iter, restricted_globals, restricted_locals)
            for item in iter_val:
                if isinstance(node.target, ast.Name):
                    restricted_locals[node.target.id] = item
                for stmt in node.body:
                    RestrictedCodeExecutor._execute_node(stmt, restricted_globals, restricted_locals)
        elif isinstance(node, ast.If):
            test_val = RestrictedCodeExecutor._evaluate_expr(node.test, restricted_globals, restricted_locals)
            if test_val:
                for stmt in node.body:
                    RestrictedCodeExecutor._execute_node(stmt, restricted_globals, restricted_locals)
            else:
                for stmt in node.orelse:
                    RestrictedCodeExecutor._execute_node(stmt, restricted_globals, restricted_locals)
        elif isinstance(node, ast.While):
            while RestrictedCodeExecutor._evaluate_expr(node.test, restricted_globals, restricted_locals):
                for stmt in node.body:
                    RestrictedCodeExecutor._execute_node(stmt, restricted_globals, restricted_locals)

    @staticmethod
    def _evaluate_expr(node, restricted_globals, restricted_locals):
        """Safely evaluate expressions"""
        if isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.Str):
            return node.s
        elif isinstance(node, ast.Name):
            if node.id in restricted_locals:
                return restricted_locals[node.id]
            elif node.id in restricted_globals:
                return restricted_globals[node.id]
            else:
                raise NameError(f"name '{node.id}' is not defined")
        elif isinstance(node, ast.BinOp):
            left = RestrictedCodeExecutor._evaluate_expr(node.left, restricted_globals, restricted_locals)
            right = RestrictedCodeExecutor._evaluate_expr(node.right, restricted_globals, restricted_locals)
            return RestrictedCodeExecutor._apply_binop(node.op, left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = RestrictedCodeExecutor._evaluate_expr(node.operand, restricted_globals, restricted_locals)
            return RestrictedCodeExecutor._apply_unaryop(node.op, operand)
        elif isinstance(node, ast.Compare):
            left = RestrictedCodeExecutor._evaluate_expr(node.left, restricted_globals, restricted_locals)
            for op, comparator in zip(node.ops, node.comparators):
                right = RestrictedCodeExecutor._evaluate_expr(comparator, restricted_globals, restricted_locals)
                if not RestrictedCodeExecutor._apply_compare(op, left, right):
                    return False
                left = right
            return True
        elif isinstance(node, ast.Call):
            func = RestrictedCodeExecutor._evaluate_expr(node.func, restricted_globals, restricted_locals)
            args = [RestrictedCodeExecutor._evaluate_expr(arg, restricted_globals, restricted_locals) for arg in node.args]
            return func(*args)
        elif isinstance(node, ast.List):
            return [RestrictedCodeExecutor._evaluate_expr(elt, restricted_globals, restricted_locals) for elt in node.elts]
        elif isinstance(node, ast.Dict):
            return {RestrictedCodeExecutor._evaluate_expr(k, restricted_globals, restricted_locals): 
                    RestrictedCodeExecutor._evaluate_expr(v, restricted_globals, restricted_locals) 
                    for k, v in zip(node.keys, node.values)}
        elif isinstance(node, ast.Tuple):
            return tuple(RestrictedCodeExecutor._evaluate_expr(elt, restricted_globals, restricted_locals) for elt in node.elts)
        else:
            raise ValueError(f"Unsupported expression type: {type(node)}")

    @staticmethod
    def _apply_binop(op, left, right):
        """Apply binary operations safely"""
        if isinstance(op, ast.Add):
            return left + right
        elif isinstance(op, ast.Sub):
            return left - right
        elif isinstance(op, ast.Mult):
            return left * right
        elif isinstance(op, ast.Div):
            return left / right
        elif isinstance(op, ast.FloorDiv):
            return left // right
        elif isinstance(op, ast.Mod):
            return left % right
        elif isinstance(op, ast.Pow):
            return left ** right
        else:
            raise ValueError(f"Unsupported binary operator: {type(op)}")

    @staticmethod
    def _apply_unaryop(op, operand):
        """Apply unary operations safely"""
        if isinstance(op, ast.UAdd):
            return +operand
        elif isinstance(op, ast.USub):
            return -operand
        elif isinstance(op, ast.Not):
            return not operand
        else:
            raise ValueError(f"Unsupported unary operator: {type(op)}")

    @staticmethod
    def _apply_compare(op, left, right):
        """Apply comparison operations safely"""
        if isinstance(op, ast.Eq):
            return left == right
        elif isinstance(op, ast.NotEq):
            return left != right
        elif isinstance(op, ast.Lt):
            return left < right
        elif isinstance(op, ast.LtE):
            return left <= right
        elif isinstance(op, ast.Gt):
            return left > right
        elif isinstance(op, ast.GtE):
            return left >= right
        else:
            raise ValueError(f"Unsupported comparison operator: {type(op)}")

